func NewCreateSecretPayload(body *CreateSecretRequestBody, token string) *secrets.CreateSecretPayload {
	v := &secrets.CreateSecretPayload{
		Key:         *body.Key,
		Value:       *body.Value,
		Environment: *body.Environment,
		ProjectID:   *body.ProjectID,
	}
	v.Token = token

	return v
}

